const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const app = express();
const server = http.createServer(app);
const io = socketIo(server);

const SECRET_KEY = 'your-secret-key';
const players = new Map();
const sessions = new Map();
const leaderboard = [];

app.use(express.json());

// Authentication middleware
const authenticate = (req, res, next) => {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Access denied' });
  
  try {
    const decoded = jwt.verify(token, SECRET_KEY);
    req.user = decoded;
    next();
  } catch (error) {
    res.status(401).json({ error: 'Invalid token' });
  }
};

// Register endpoint
app.post('/register', async (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) return res.status(400).json({ error: 'Username and password required' });
  
  if (players.has(username)) return res.status(400).json({ error: 'Username already exists' });
  
  const hashedPassword = await bcrypt.hash(password, 10);
  players.set(username, { password: hashedPassword, score: 0 });
  res.json({ message: 'User registered successfully' });
});

// Login endpoint
app.post('/login', async (req, res) => {
  const { username, password } = req.body;
  if (!username || !password) return res.status(400).json({ error: 'Username and password required' });
  
  const player = players.get(username);
  if (!player) return res.status(400).json({ error: 'Invalid credentials' });
  
  const isValid = await bcrypt.compare(password, player.password);
  if (!isValid) return res.status(400).json({ error: 'Invalid credentials' });
  
  const token = jwt.sign({ username }, SECRET_KEY, { expiresIn: '24h' });
  res.json({ token, username });
});

// Get leaderboard
app.get('/leaderboard', (req, res) => {
  const sortedLeaderboard = [...leaderboard].sort((a, b) => b.score - a.score).slice(0, 10);
  res.json(sortedLeaderboard);
});

io.on('connection', (socket) => {
  let username = null;
  
  socket.on('authenticate', (data) => {
    const { token } = data;
    try {
      const decoded = jwt.verify(token, SECRET_KEY);
      username = decoded.username;
      
      if (!players.has(username)) {
        socket.emit('auth-error', { error: 'Invalid user' });
        return;
      }
      
      socket.join(username);
      socket.emit('authenticated', { username });
      
      // Send current leaderboard to authenticated user
      const sortedLeaderboard = [...leaderboard].sort((a, b) => b.score - a.score).slice(0, 10);
      socket.emit('leaderboard-update', sortedLeaderboard);
      
    } catch (error) {
      socket.emit('auth-error', { error: 'Authentication failed' });
    }
  });
  
  socket.on('update-score', (data) => {
    if (!username) return;
    
    const { score } = data;
    if (typeof score !== 'number' || score < 0) return;
    
    // Update player score
    const player = players.get(username);
    if (player) {
      player.score = Math.max(player.score, score);
      
      // Update leaderboard
      const existingIndex = leaderboard.findIndex(p => p.username === username);
      if (existingIndex >= 0) {
        leaderboard[existingIndex].score = player.score;
      } else {
        leaderboard.push({ username, score: player.score });
      }
      
      // Broadcast updated leaderboard
      const sortedLeaderboard = [...leaderboard].sort((a, b) => b.score - a.score).slice(0, 10);
      io.emit('leaderboard-update', sortedLeaderboard);
    }
  });
  
  socket.on('disconnect', () => {
    if (username) {
      console.log(`${username} disconnected`);
    }
  });
});

server.listen(3000, () => {
  console.log('Server running on port 3000');
});